import os
from google.cloud import storage, firestore, pubsub_v1
from google.auth.transport.requests import Request
from google.oauth2 import service_account
import json

# Initialize clients
storage_client = storage.Client()
firestore_client = firestore.Client()
publisher = pubsub_v1.PublisherClient()

# Environment variables
PROJECT_ID = os.getenv('GCP_PROJECT')
TOPIC_NAME = os.getenv('PUBSUB_TOPIC')
SERVICE_ACCOUNT_FILE = os.getenv('SERVICE_ACCOUNT_FILE')

# Load service account credentials
credentials = service_account.Credentials.from_service_account_file(
    SERVICE_ACCOUNT_FILE,
    scopes=["https://www.googleapis.com/auth/cloud-platform"]
)

def validate_input(data):
    # Implement validation logic for untrusted input
    if not isinstance(data, dict):
        raise ValueError("Invalid input format")
    # Add more validation as needed

def process_file(event, context):
    bucket_name = event['bucket']
    file_name = event['name']

    # Validate input
    validate_input(event)

    # Access the file from Cloud Storage
    bucket = storage_client.bucket(bucket_name)
    blob = bucket.blob(file_name)
    file_content = blob.download_as_text()

    # Process file content (example: parse JSON)
    try:
        file_data = json.loads(file_content)
    except json.JSONDecodeError:
        raise ValueError("Invalid JSON format")

    # Write to Firestore
    doc_ref = firestore_client.collection('processed_files').document(file_name)
    doc_ref.set(file_data)

    # Publish to Pub/Sub
    topic_path = publisher.topic_path(PROJECT_ID, TOPIC_NAME)
    future = publisher.publish(topic_path, json.dumps(file_data).encode('utf-8'))
    future.result()

    print(f"Processed file {file_name} from bucket {bucket_name}")

# Ensure the function is using the correct service account
def main(event, context):
    if not credentials.valid:
        credentials.refresh(Request())
    process_file(event, context)